13	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: any];
14	  newBadge?: boolean;
15	};
16	
17	const GuestManagementSection: FC<GuestManagementSectionProps> = ({
18	  hyperConvergeConfiguration,
19	  newBadge,
20	}) => {
21	  const { t } = useKubevirtTranslation();
22	
23	  return (
24	    <ExpandSection toggleText={t('Guest management')}>
